sys_variable_value.value:
(function execute(inputs, outputs) {
    try {
        var payloadsList = [];
        var timeCardGR = new GlideRecord('time_card');
        
        if (timeCardGR.get(inputs.time_card_id)) {
            var weekStartStr = timeCardGR.getValue('week_starts_on'); 

            var daysMapping = [
                { field: 'sunday',    offset: 0 },
                { field: 'monday',    offset: 1 },
                { field: 'tuesday',   offset: 2 },
                { field: 'wednesday', offset: 3 },
                { field: 'thursday',  offset: 4 },
                { field: 'friday',    offset: 5 },
                { field: 'saturday',  offset: 6 }
            ];

            for (var i = 0; i < daysMapping.length; i++) {
                var dayInfo = daysMapping[i];
                var hours = parseFloat(timeCardGR.getValue(dayInfo.field)) || 0;

                if (hours > 0) {
                    var gdt = new GlideDateTime(weekStartStr);
                    gdt.addDaysLocalTime(dayInfo.offset);
                    
                    var dateOnly = gdt.getDate().toString();
                    var dateUtcFormatted = dateOnly + "T09:00:00.0000000+00:00"; 
                    var durationInMinutes = Math.round(hours * 60);

                    var entryPayload = {
                        "userId": inputs.user_id, 
                        "taskId": inputs.task_id, 
                        "dateUtc": dateUtcFormatted,
                        "duration": durationInMinutes,
                        "description": "ServiceNow Time Entry - " + dayInfo.field
                    };

                    payloadsList.push(entryPayload);
                }
            }
        }

        // Retorna a String JSON compactada (sem espaços extras) para o Flow
        outputs.time_entries_json = JSON.stringify(payloadsList);

    } catch (ex) {
        outputs.time_entries_json = "[]";
    }
})(inputs, outputs);

